import xml.etree.ElementTree as ET

def extract_members(xml_file, filter_text=None):
    tree = ET.parse(xml_file)
    root = tree.getroot()

    members = {}
    current_type = None

    for member in root.findall('.//member'):
        name = member.get('name', '')
        summary = member.find('summary')
        summary_text = summary.text.strip() if summary is not None and summary.text else ""

        if name.startswith('T:'):
            current_type = name[2:]
            if filter_text is None or filter_text in current_type:
                members[current_type] = {'type': 'class', 'summary': summary_text}
        elif name.startswith('M:') and current_type:
            if filter_text is None or filter_text in current_type:
                method_name = name.split('.')[-1].split('(')[0]
                if current_type not in members:
                    members[current_type] = {'methods': []}
                if 'methods' not in members[current_type]:
                    members[current_type]['methods'] = []
                members[current_type]['methods'].append({'name': method_name, 'sig': name})
        elif name.startswith('P:') and current_type:
            if filter_text is None or filter_text in current_type:
                prop_name = name.split('.')[-1]
                if current_type not in members:
                    members[current_type] = {'properties': []}
                if 'properties' not in members[current_type]:
                    members[current_type]['properties'] = []
                members[current_type]['properties'].append(prop_name)

    return members

