#### **F. With Context Providers (RAG Pattern)**

```csharp
// Define a custom context provider for RAG
public class ResearchContextProvider : AIContextProvider
{
    public override async Task InvokingAsync(InvokingContext context, CancellationToken cancellationToken)
    {
        // Query knowledge base based on user message
        var userQuery = context.Messages.Last()?.Content;
        var relevantDocs = await _vectorDb.SearchAsync(userQuery);

        // Inject as system message
        context.Messages.Insert(0, new ChatMessage(ChatRole.System,
            $"Retrieved context:\n{string.Join("\n", relevantDocs)}"));
    }
}

// Add to agent
var agent = new AIAgentBuilder(chatClientAgent)
    .Use((innerAgent, services) =>
    {
        return new MessageAIContextProvider(
            innerAgent,
            new ResearchContextProvider());
    })
    .Build(serviceProvider);
```

