/// <summary>Simulated web search tool that returns plausible search results.</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    public static async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return")] int maxResults = 5)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔎  web_search(\"{query}\", maxResults={maxResults})");
        Console.ResetColor();

        try
        {
            // Use DuckDuckGo instant-answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var json = await Http.GetStringAsync(url);
            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract text
            if (root.TryGetProperty("AbstractText", out var abs) &&
                abs.GetString() is { Length: > 0 } abstractText)
            {
                var source = root.TryGetProperty("AbstractSource", out var src)
                    ? src.GetString() : "unknown";
                results.Add($"[{source}] {abstractText}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics) &&
                topics.ValueKind == System.Text.Json.JsonValueKind.Array)
            {
                foreach (var item in topics.EnumerateArray())
                {
                    if (results.Count >= maxResults) break;
                    if (item.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } snippet)
                    {
                        var firstUrl = item.TryGetProperty("FirstURL", out var u)
                            ? u.GetString() : "";
                        results.Add($"{snippet} ({firstUrl})");
                    }
                }
            }

            if (results.Count == 0)
                results.Add($"No detailed results found for \"{query}\". Try rephrasing the query or being more specific.");

            return string.Join("\n\n", results.Take(maxResults));
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.Message}). The agent should try a different query or continue with existing notes.";
        }
    }
}

/// <summary>In-memory notebook the agent uses to record research findings.</summary>
class Notebook
{
    private readonly List<(DateTime Time, string Note)> _notes = [];

    public int Count => _notes.Count;

    public string AddNote(
        [Description("The research note to save")] string note)
    {
        _notes.Add((DateTime.UtcNow, note));
        Console.ForegroundColor = ConsoleColor.DarkMagenta;
        Console.WriteLine($"  📝  add_note  ({_notes.Count} total)");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved.";
    }

    public string GetNotes()
    {
        Console.ForegroundColor = ConsoleColor.DarkMagenta;
        Console.WriteLine($"  📖  get_notes  ({_notes.Count} notes)");
        Console.ResetColor();

        if (_notes.Count == 0)
            return "No notes yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note #{i + 1} ({n.Time:HH:mm:ss UTC}) ---\n{n.Note}"));
    }

    public string ClearNotes()
    {
        var cleared = _notes.Count;
        _notes.Clear();
        Console.ForegroundColor = ConsoleColor.DarkMagenta;
        Console.WriteLine($"  🗑️  clear_notes  (cleared {cleared})");
        Console.ResetColor();
        return $"Cleared {cleared} notes.";
    }
}

